const html = "<!DOCTYPE html>\n<html lang=\"fr\">\n<head>\n    <meta charset=\"UTF-8\">\n    <link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 32 32'%3E%3Ccircle cx='16' cy='16' r='15' fill='%23E3350D'/%3E%3Ccircle cx='16' cy='16' r='15' fill='white' clip-path='inset(50%25 0 0 0)'/%3E%3Crect x='1' y='14.5' width='30' height='3' fill='%230B1623'/%3E%3Ccircle cx='16' cy='16' r='5' fill='white' stroke='%230B1623' stroke-width='2.5'/%3E%3C/svg%3E\">\n    <meta name=\"description\" content=\"PokéInvest — Inventaire de vos cartes Pokémon à l'unité.\">\n    <meta name=\"theme-color\" content=\"#0B1623\">\n    <meta name=\"apple-mobile-web-app-capable\" content=\"yes\">\n    <meta name=\"apple-mobile-web-app-status-bar-style\" content=\"black-translucent\">\n    <meta name=\"apple-mobile-web-app-title\" content=\"PokéInvest\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, viewport-fit=cover\">\n    <title>PokéInvest — Cartes à l'unité</title>\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"/dashboard/style.css\">\n    </head>\n<body>\n<div class=\"toast-container\" id=\"toastContainer\"></div>\n<div class=\"confirm-overlay\" id=\"confirmOverlay\">\n    <div class=\"confirm-dialog\">\n        <div class=\"confirm-title\" id=\"confirmTitle\"></div>\n        <div class=\"confirm-body\" id=\"confirmBody\"></div>\n        <div class=\"confirm-actions\">\n            <button class=\"btn-cancel\" id=\"confirmCancel\">Annuler</button>\n            <button class=\"btn-submit\" id=\"confirmOk\" style=\"background:var(--red);\">Supprimer</button>\n        </div>\n    </div>\n</div>\n<div class=\"mobile-header\">\n    <div class=\"logo-mark\">\n        <div class=\"logo-ball\"></div>\n        <div class=\"logo-text\">PokéInvest</div>\n    </div>\n    <button class=\"mobile-theme-toggle\" onclick=\"toggleTheme()\" aria-label=\"Basculer le thème\">\n        <svg id=\"mobileThemeIcon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"5\"/><path d=\"M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42\"/></svg>\n    </button>\n</div>\n<aside class=\"sidebar\">\n    <div class=\"sidebar-logo\">\n        <div class=\"logo-mark\">\n            <div class=\"logo-ball\"></div>\n            <div class=\"logo-text\">PokéInvest<span>Portfolio Tracker</span></div>\n        </div>\n    </div>\n    <nav class=\"nav\">\n        <div class=\"nav-section\">Navigation</div>\n        <a href=\"/dashboard\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg></span>Tableau de bord</a>\n        <a href=\"/dashboard/cartes_unite\" class=\"active\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"2\" y=\"4\" width=\"14\" height=\"18\" rx=\"2\"/><path d=\"M10 4h6a2 2 0 0 1 2 2v12\"/><path d=\"M6 8h4M6 12h4\"/></svg></span>Cartes à l'unité</a>\n        <a href=\"/dashboard/cartes_pca\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z\"/></svg></span>Cartes Gradées</a>\n        <a href=\"/dashboard/items_scelles\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 8V21H3V8\"/><path d=\"M23 3H1v5h22V3z\"/><path d=\"M10 12h4\"/></svg></span>Items Scellés</a>\n        <a href=\"/dashboard/mastersets\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 19.5A2.5 2.5 0 0 1 6.5 17H20\"/><path d=\"M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z\"/></svg></span>Mastersets</a>\n        <div class=\"nav-section\" style=\"margin-top:4px;\">Outils</div>\n        <a href=\"#\"><span class=\"nav-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42\"/></svg></span>Référentiel Séries</a>\n    </nav>\n    <div class=\"sidebar-footer\">\n        <a href=\"/dashboard/profile\" class=\"user-pill\" style=\"text-decoration:none;\">\n            <div class=\"user-avatar\" id=\"userAvatar\">I</div>\n            <div><div class=\"user-name\" id=\"userName\">Investisseur</div><div class=\"user-role\" id=\"userRole\">Dresseur·se</div></div>\n        </a>\n        <button onclick=\"handleLogout()\" title=\"Se déconnecter\" style=\"display:flex;align-items:center;gap:6px;background:transparent;border:none;color:var(--muted);cursor:pointer;font-size:11px;padding:6px 4px;border-radius:8px;transition:color .2s;width:100%;margin-bottom:4px;\" onmouseover=\"this.style.color='var(--red)'\" onmouseout=\"this.style.color='var(--muted)'\">\n            <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4\"/><polyline points=\"16 17 21 12 16 7\"/><line x1=\"21\" y1=\"12\" x2=\"9\" y2=\"12\"/></svg>\n            Se déconnecter\n        </button>\n        <button class=\"theme-toggle\" id=\"themeToggle\" onclick=\"toggleTheme()\" aria-label=\"Basculer le thème\">\n            <svg id=\"themeIcon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"5\"/><path d=\"M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42\"/></svg>\n            <span class=\"tt-label\" id=\"themeLabel\">Mode sombre</span>\n        </button>\n    </div>\n</aside>\n<main class=\"main\">\n    <div class=\"page-header\">\n        <div>\n            <h1 class=\"page-title\">Cartes à l'unité</h1>\n            <p class=\"page-subtitle\">Inventaire · Tri et recherche instantanés</p>\n        </div>\n        <div style=\"display:flex;gap:8px;align-items:center;\">\n            <button class=\"btn-scan\" onclick=\"openScanModal()\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 7V5a2 2 0 0 1 2-2h2\"/><path d=\"M17 3h2a2 2 0 0 1 2 2v2\"/><path d=\"M21 17v2a2 2 0 0 1-2 2h-2\"/><path d=\"M7 21H5a2 2 0 0 1-2-2v-2\"/><rect x=\"7\" y=\"7\" width=\"10\" height=\"10\" rx=\"1\"/></svg> Scanner</button>\n            <button class=\"btn-add\" onclick=\"openModal()\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 5v14M5 12h14\"/></svg> Ajouter</button>\n        </div>\n    </div>\n\n    <div class=\"top-bar\">\n        <div class=\"search-wrap\">\n            <span class=\"search-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/></svg></span>\n            <input type=\"text\" id=\"searchInput\" placeholder=\"Rechercher…\" oninput=\"applyFiltersAndSort()\" aria-label=\"Rechercher\">\n        </div>\n        <div class=\"bar-right\">\n            <div class=\"view-toggle\">\n                <button class=\"view-btn active\" id=\"btnViewList\" onclick=\"setView('list')\" title=\"Vue liste\">\n                    <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><line x1=\"8\" y1=\"6\" x2=\"21\" y2=\"6\"/><line x1=\"8\" y1=\"12\" x2=\"21\" y2=\"12\"/><line x1=\"8\" y1=\"18\" x2=\"21\" y2=\"18\"/><line x1=\"3\" y1=\"6\" x2=\"3.01\" y2=\"6\"/><line x1=\"3\" y1=\"12\" x2=\"3.01\" y2=\"12\"/><line x1=\"3\" y1=\"18\" x2=\"3.01\" y2=\"18\"/></svg>\n                </button>\n                <button class=\"view-btn\" id=\"btnViewGallery\" onclick=\"setView('gallery')\" title=\"Vue galerie\">\n                    <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg>\n                </button>\n            </div>\n            <div class=\"count-badge\" id=\"totalItemsBadge\">0</div>\n        </div>\n    </div>\n\n    <div class=\"table-wrap\" id=\"listView\">\n        <table id=\"dataTable\">\n            <thead><tr>\n<th class=\"cb-th\"><input type=\"checkbox\" class=\"row-cb\" id=\"selectAllCb\" onchange=\"toggleSelectAll(this)\" title=\"Tout sélectionner\"></th>\n<th onclick=\"sortTable(0)\">Carte</th>\n<th onclick=\"sortTable(1)\">N°</th>\n<th onclick=\"sortTable(2)\">Bloc</th>\n<th onclick=\"sortTable(3)\">Série</th>\n<th onclick=\"sortTable(4)\">Achat</th>\n<th onclick=\"sortTable(5)\">Cote</th>\n<th onclick=\"sortTable(6)\">Plus-value</th>\n<th style=\"text-align:right;cursor:default\">Actions</th></tr></thead>\n            <tbody id=\"tableBody\"></tbody>\n        </table>\n    </div>\n    <div id=\"galleryView\" style=\"display:none\">\n        <div class=\"gallery-grid\" id=\"galleryGrid\"></div>\n    </div>\n</main>\n<nav class=\"mobile-bottom-nav\">\n    <a href=\"/dashboard\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg><span>Accueil</span></a>\n    <a href=\"/dashboard/cartes_unite\" class=\"active\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"2\" y=\"4\" width=\"14\" height=\"18\" rx=\"2\"/><path d=\"M10 4h6a2 2 0 0 1 2 2v12\"/><path d=\"M6 8h4M6 12h4\"/></svg><span>À l'unité</span></a>\n    <a href=\"/dashboard/cartes_pca\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z\"/></svg><span>Gradées</span></a>\n    <a href=\"/dashboard/items_scelles\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 8V21H3V8\"/><path d=\"M23 3H1v5h22V3z\"/><path d=\"M10 12h4\"/></svg><span>Scellés</span></a>\n    <a href=\"/dashboard/mastersets\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 19.5A2.5 2.5 0 0 1 6.5 17H20\"/><path d=\"M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z\"/></svg><span>Sets</span></a>\n    </nav>\n\n<div class=\"modal-overlay\" id=\"modalOverlay\">\n    <div class=\"modal\">\n        <div class=\"modal-head\">\n            <span class=\"modal-title\" id=\"modalTitle\">Ajouter</span>\n            <button class=\"modal-close\" onclick=\"closeModal()\" aria-label=\"Fermer\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M18 6 6 18M6 6l12 12\"/></svg></button>\n        </div>\n        <form id=\"itemForm\" onsubmit=\"handleFormSubmit(event)\">\n            <input type=\"hidden\" id=\"formItemIndex\" value=\"-1\">\n            <div class=\"form-row wide\">\n                <div class=\"form-group\">\n                    <label for=\"formCarte\">Nom de la carte</label>\n                    <input type=\"text\" id=\"formCarte\" placeholder=\"Ex: Dracaufeu, Pikachu VMAX…\" required>\n                </div>\n                <div class=\"form-group\">\n                    <label for=\"formNumero\">Numéro</label>\n                    <input type=\"text\" id=\"formNumero\" placeholder=\"004/165\" required>\n                </div>\n            </div>\n            <div class=\"form-group\">\n                <label for=\"formBloc\">Bloc</label>\n                <select id=\"formBloc\" required>\n                    <option value=\"ECARLATE ET VIOLET\">Écarlate et Violet</option>\n                    <option value=\"EPEE ET BOUCLIER\">Épée et Bouclier</option>\n                    <option value=\"SOLEIL ET LUNE\">Soleil et Lune</option>\n                    <option value=\"XY\">XY</option>\n                    <option value=\"MEGA EVOLUTION\">Mega Evolution</option>\n                    <option value=\"Inconnu\">Autre / Inconnu</option>\n                </select>\n            </div>\n            <div class=\"form-group\">\n                <label for=\"formSerie\">Série / Extension</label>\n                <input type=\"text\" id=\"formSerie\" placeholder=\"Ex: 151, Évolutions Prismatiques…\" required>\n            </div>\n            <div class=\"form-row\">\n                <div class=\"form-group\">\n                    <label for=\"formPrix\">Prix d'achat (€)</label>\n                    <input type=\"number\" id=\"formPrix\" step=\"0.01\" min=\"0\" placeholder=\"0,00\" required>\n                </div>\n                <div class=\"form-group\">\n                    <label for=\"formCote\">Cote actuelle (€)</label>\n                    <input type=\"number\" id=\"formCote\" step=\"0.01\" min=\"0\" placeholder=\"0,00\" required>\n                </div>\n            </div>\n            <div class=\"form-actions\">\n                <button type=\"button\" class=\"btn-cancel\" onclick=\"closeModal()\">Annuler</button>\n                <button type=\"submit\" id=\"btnSubmitForm\" class=\"btn-submit\">Ajouter</button>\n            </div>\n        </form>\n    </div>\n</div>\n\n<script>\n    const fmt = n => new Intl.NumberFormat('fr-FR',{style:'currency',currency:'EUR'}).format(n);\n    const EDIT_ICON = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7\"/><path d=\"M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z\"/></svg>`;\n    const TRASH_ICON = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"3 6 5 6 21 6\"/><path d=\"M19 6l-1 14H6L5 6\"/><path d=\"M10 11v6M14 11v6\"/><path d=\"M9 6V4h6v2\"/></svg>`;\n\n    function blocClass(b){\n        const s = (b||'').toUpperCase();\n        if(s.includes('ECARLATE')||s.includes('VIOLET')) return 'ev';\n        if(s.includes('EPEE')||s.includes('BOUCLIER')) return 'eb';\n        if(s.includes('MEGA')) return 'me';\n        return 'other';\n    }\n\n    let cartesData = [];\n    let _currentUser = null;\n    let _supabaseClient = null;\n    let currentSort = {col:-1, asc:true};\n\n    function renderTable(data){\n        const tbody = document.getElementById('tableBody');\n        tbody.innerHTML = '';\n        if(!data.length){\n            tbody.innerHTML = `<tr>colspan=\"9\"<div class=\"empty-icon\">${CARDS_ICON}</div><p>Aucune carte trouvée.</p></div></td></tr>`;\n        } else {\n            data.forEach(row => {\n                const ri = cartesData.indexOf(row);\n                const ben = row.benef;\n                const bc = ben>0?'positive':ben<0?'negative':'neutral';\n                const bt = ben>0?'+'+fmt(ben):fmt(ben);\n                const tr = document.createElement('tr');\n                tr.innerHTML = `\n                                        <td class=\"cb-td\"><input type=\"checkbox\" class=\"row-cb\" data-idx=\"${ri}\" onchange=\"toggleRowSelect(this)\"></td>\n                    <td class=\"name-cell\">${row.carte}</td>\n                    <td data-label=\"N°\"><span class=\"num-badge\">${row.numero}</span></td>\n                    <td data-label=\"Bloc\"><span class=\"bloc-chip ${blocClass(row.bloc)}\">${row.bloc}</span></td>\n                    <td data-label=\"Série\" style=\"color:var(--muted);font-size:13px;\">${row.serie}</td>\n                    <td data-label=\"Achat\" class=\"price-cell\">${fmt(row.prix_achat)}</td>\n                    <td data-label=\"Cote\" class=\"price-cell\">${fmt(row.cote)}</td>\n                    <td data-label=\"Plus-value\" class=\"${bc}\">${bt}</td>\n                    <td><div class=\"actions\">\n                        <button class=\"act-btn ebay\" id=\"ebay-btn-${ri}\" onclick=\"fetchEbayPrice(this, '${row.carte} ${row.numero} pokemon card', cartesData[${ri}], ${ri})\" title=\"Actualiser prix eBay\">${EBAY_ICON_SVG}</button>\n                        <button class=\"act-btn edit\" onclick=\"openEditModal(${ri})\" title=\"Modifier\">${EDIT_ICON}</button>\n                        <button class=\"act-btn del\" onclick=\"deleteItem(${ri})\" title=\"Supprimer\">${TRASH_ICON}</button>\n                    </div></td>`;\n                tbody.appendChild(tr);\n            });\n        }\n        const n = data.length;\n        document.getElementById('totalItemsBadge').textContent = n + ' carte' + (n>1?'s':'');\n    }\n\n    function applyFiltersAndSort(){\n        const q = document.getElementById('searchInput').value.toLowerCase();\n        let d = cartesData.filter(r => ['carte','numero','bloc','serie'].some(k => String(r[k]).toLowerCase().includes(q)));\n        if(currentSort.col !== -1){\n            const keys = [[4,5,6]];\n            const k = keys[currentSort.col];\n            const asc = currentSort.asc;\n            const numCols = [4,5,6];\n            const isNum = numCols.includes(currentSort.col);\n            d.sort((a,b) => isNum ? (asc ? (parseFloat(a[k])||0)-(parseFloat(b[k])||0) : (parseFloat(b[k])||0)-(parseFloat(a[k])||0))\n                                 : (asc ? a[k].localeCompare(b[k]) : b[k].localeCompare(a[k])));\n        }\n        _lastGalleryData = d;\n        renderTable(d);\n        if (typeof _currentView !== 'undefined' && _currentView === 'gallery') renderGallery(d);\n    }\n\n    function sortTable(col){\n        document.querySelectorAll('th').forEach(t => t.classList.remove('sort-asc','sort-desc'));\n        const asc = currentSort.col === col ? !currentSort.asc : true;\n        currentSort = {col, asc};\n        document.querySelectorAll('th')[col].classList.add(asc ? 'sort-asc' : 'sort-desc');\n        applyFiltersAndSort();\n    }\n\n    async function deleteItem(i){\n        showConfirm('Supprimer ?', 'Cette action est irréversible.', async function() {\n            const id = cartesData[i].id;\n            const { error } = await _supabaseClient.from('cartes_unite').delete().eq('id', id);\n            if (!error) { cartesData.splice(i,1); applyFiltersAndSort(); showToast('Élément supprimé', 'success'); }\n            else showToast('Erreur lors de la suppression', 'error');\n        });\n    }\n\n    function openModal(){\n        document.getElementById('itemForm').reset();\n        document.getElementById('formItemIndex').value = '-1';\n        document.getElementById('modalTitle').textContent = 'Ajouter';\n        document.getElementById('btnSubmitForm').textContent = 'Ajouter';\n        document.getElementById('modalOverlay').classList.add('active');\n    }\n\n    const CARDS_ICON = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"2\" y=\"4\" width=\"14\" height=\"18\" rx=\"2\"/><path d=\"M10 4h6a2 2 0 0 1 2 2v12\"/></svg>`;\n\n    function openEditModal(i){\n        const r = cartesData[i];\n        document.getElementById('formItemIndex').value = i;\n        document.getElementById('formCarte').value = r.carte;\n        document.getElementById('formNumero').value = r.numero;\n        const s = document.getElementById('formBloc');\n        if(!Array.from(s.options).some(o=>o.value===r.bloc)) s.add(new Option(r.bloc,r.bloc));\n        s.value = r.bloc;\n        document.getElementById('formSerie').value = r.serie;\n        document.getElementById('formPrix').value = r.prix_achat;\n        document.getElementById('formCote').value = r.cote;\n        document.getElementById('modalTitle').textContent = 'Modifier la carte';\n        document.getElementById('btnSubmitForm').textContent = 'Enregistrer';\n        document.getElementById('modalOverlay').classList.add('active');\n    }\n\n    async function handleFormSubmit(e){\n        e.preventDefault();\n        const btn = document.getElementById('btnSubmitForm');\n        btn.disabled = true; btn.textContent = 'Enregistrement…';\n        const carte = document.getElementById('formCarte').value;\n        const numero = document.getElementById('formNumero').value;\n        const bloc = document.getElementById('formBloc').value;\n        const serie = document.getElementById('formSerie').value.toUpperCase();\n        const prix = parseFloat(document.getElementById('formPrix').value);\n        const cote = parseFloat(document.getElementById('formCote').value);\n        const idx = parseInt(document.getElementById('formItemIndex').value);\n        const payload = { user_id: _currentUser.id, carte, numero, bloc, serie, prix_achat: prix, cote };\n        if(idx===-1){\n            const { data, error } = await _supabaseClient.from('cartes_unite').insert(payload).select().single();\n            if (!error) cartesData.unshift({ ...data, benef: data.cote - data.prix_achat });\n            else { showToast('Erreur lors de l\\'ajout', 'error'); btn.disabled=false; btn.textContent='Ajouter'; return; }\n        } else {\n            const id = cartesData[idx].id;\n            const { data, error } = await _supabaseClient.from('cartes_unite').update(payload).eq('id', id).select().single();\n            if (!error) Object.assign(cartesData[idx], { ...data, benef: data.cote - data.prix_achat });\n            else { showToast('Erreur lors de la modification', 'error'); btn.disabled=false; btn.textContent='Enregistrer'; return; }\n        }\n        btn.disabled=false;\n        applyFiltersAndSort(); closeModal();\n    }\n\n    function closeModal(){ document.getElementById('modalOverlay').classList.remove('active'); }\n\n    document.getElementById('modalOverlay').addEventListener('click', e => {\n        if(e.target === document.getElementById('modalOverlay')) closeModal();\n    });\n\n    // ===== EBAY PRICE FETCH =====\n    const EBAY_ICON_SVG = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 8v4l2.5 2.5\"/></svg>`;\n    const SPIN_ICON = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 12a9 9 0 1 1-6.219-8.56\"/></svg>`;\n\n    const tooltip = document.createElement('div');\n    tooltip.className = 'ebay-tooltip';\n    document.body.appendChild(tooltip);\n\n    async function fetchEbayPrice(btn, query, dataObj, rowIndex) {\n        btn.classList.add('loading');\n        btn.innerHTML = SPIN_ICON;\n        btn.disabled = true;\n\n        try {\n            const res = await fetch(`/api/ebay-price?q=${encodeURIComponent(query)}`);\n            const data = await res.json();\n\n            btn.disabled = false;\n            btn.classList.remove('loading');\n\n            if (data.error || data.price === null) {\n                btn.classList.add('error');\n                btn.title = data.error || 'Aucun résultat eBay';\n                btn.innerHTML = EBAY_ICON_SVG;\n                setTimeout(() => btn.classList.remove('error'), 3000);\n                return;\n            }\n\n            dataObj.cote = data.price;\n            dataObj.benef = Math.round((data.price - dataObj.prix_achat) * 100) / 100;\n            if (dataObj.id) await _supabaseClient.from('cartes_unite').update({ cote: data.price }).eq('id', dataObj.id);\n\n            btn.classList.add('success');\n            btn.innerHTML = EBAY_ICON_SVG;\n            setTimeout(() => { btn.classList.remove('success'); applyFiltersAndSort(); }, 800);\n\n            const items = data.items || [];\n            if (items.length) {\n                tooltip.innerHTML = `\n                    <div class=\"tt-price\">Médiane : ${fmt(data.price)}</div>\n                    <div class=\"tt-count\">${data.count} annonce${data.count > 1 ? 's' : ''} eBay</div>\n                `;\n                const rect = btn.getBoundingClientRect();\n                tooltip.style.top = (rect.top + window.scrollY - tooltip.offsetHeight - 8) + 'px';\n                tooltip.style.left = Math.min(rect.left, window.innerWidth - 280) + 'px';\n                tooltip.classList.add('visible');\n                setTimeout(() => tooltip.classList.remove('visible'), 3500);\n            }\n\n        } catch(err) {\n            btn.disabled = false;\n            btn.classList.remove('loading');\n            btn.classList.add('error');\n            btn.innerHTML = EBAY_ICON_SVG;\n            btn.title = 'Erreur réseau';\n            setTimeout(() => btn.classList.remove('error'), 3000);\n        }\n    }\n\n    // ===== VIEW TOGGLE =====\n    let _currentView = 'list';\n    let _lastGalleryData = [];\n\n    // Note: applyFiltersAndSort() est appelé après le chargement Supabase\n\n    function setView(v) {\n        _currentView = v;\n        document.getElementById('btnViewList').classList.toggle('active', v === 'list');\n        document.getElementById('btnViewGallery').classList.toggle('active', v === 'gallery');\n        document.getElementById('listView').style.display = v === 'list' ? '' : 'none';\n        document.getElementById('galleryView').style.display = v === 'gallery' ? '' : 'none';\n        if (v === 'gallery') renderGallery(_lastGalleryData);\n    }\n\n    // ===== POKÉTCG IMAGE CACHE =====\n    const _imgCache = {};\n\n    async function fetchCardImage(name, numero) {\n        const cacheKey = name + '|' + numero;\n        if (_imgCache[cacheKey] !== undefined) return _imgCache[cacheKey];\n        try {\n            const res = await fetch(`https://api.pokemontcg.io/v2/cards?q=name:${encodeURIComponent(name)}&pageSize=8`);\n            const data = await res.json();\n            const cards = data.data || [];\n            let match = cards.find(c => c.number && numero.toLowerCase().includes(c.number.toLowerCase()));\n            if (!match) match = cards[0];\n            const url = match ? (match.images?.small || null) : null;\n            _imgCache[cacheKey] = url;\n            return url;\n        } catch(e) {\n            _imgCache[cacheKey] = null;\n            return null;\n        }\n    }\n\n    // ===== GALLERY RENDER =====\n    const PLACEHOLDER_CARD_G = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"2\" y=\"4\" width=\"14\" height=\"18\" rx=\"2\"/><path d=\"M10 4h6a2 2 0 0 1 2 2v12\"/><path d=\"M6 8h4M6 12h4\"/></svg>`;\n\n    function renderGallery(data) {\n        _lastGalleryData = data;\n        const grid = document.getElementById('galleryGrid');\n        grid.innerHTML = '';\n        if (!data.length) {\n            grid.innerHTML = `<div style=\"grid-column:1/-1;text-align:center;padding:48px 0;color:var(--muted);\">Aucune carte trouvée.</div>`;\n            return;\n        }\n        data.forEach(row => {\n            const ri = cartesData.indexOf(row);\n            const ben = row.benef;\n            const bc = ben>0?'positive':ben<0?'negative':'neutral';\n            const bt = ben>0?'+'+fmt(ben):fmt(ben);\n            const card = document.createElement('div');\n            card.className = 'gallery-card';\n            card.innerHTML = `\n                <div class=\"gallery-img-wrap\">\n                    <div class=\"gallery-img-placeholder\" id=\"gph-${ri}\">${PLACEHOLDER_CARD_G}</div>\n                    <img id=\"gimg-${ri}\" alt=\"${row.carte}\" class=\"loading\" style=\"display:none\">\n                    <span class=\"gallery-benef-badge ${bc}\">${bt}</span>\n                </div>\n                <div class=\"gallery-info\">\n                    <div class=\"gallery-name\">${row.carte}</div>\n                    <div class=\"gallery-sub\">${row.numero} · ${row.serie}</div>\n                    <div class=\"gallery-actions\">\n                        <button class=\"gallery-act\" onclick=\"openEditModal(${ri})\" title=\"Modifier\">${EDIT_ICON}</button>\n                        <button class=\"gallery-act del\" onclick=\"deleteItem(${ri})\" title=\"Supprimer\">${TRASH_ICON}</button>\n                    </div>\n                </div>`;\n            grid.appendChild(card);\n            fetchCardImage(row.carte, row.numero).then(url => {\n                const img = document.getElementById(`gimg-${ri}`);\n                const ph = document.getElementById(`gph-${ri}`);\n                if (url && img) {\n                    img.src = url;\n                    img.style.display = '';\n                    img.onload = () => { img.classList.remove('loading'); if(ph) ph.style.display='none'; };\n                    img.onerror = () => { img.style.display='none'; };\n                }\n            });\n        });\n    }\n\n</script>\n\n<!-- SCAN MODAL -->\n<div class=\"modal-overlay\" id=\"scanModalOverlay\">\n    <div class=\"modal scan-modal\">\n        <div class=\"modal-head\">\n            <span class=\"modal-title\">Scanner une carte</span>\n            <button class=\"modal-close\" onclick=\"closeScanModal()\" aria-label=\"Fermer\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M18 6 6 18M6 6l12 12\"/></svg></button>\n        </div>\n        <div class=\"scan-tabs\">\n            <button class=\"scan-tab active\" onclick=\"setScanTab('upload')\" id=\"tabUpload\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4\"/><polyline points=\"17 8 12 3 7 8\"/><line x1=\"12\" y1=\"3\" x2=\"12\" y2=\"15\"/></svg>\n                Importer une photo\n            </button>\n            <button class=\"scan-tab\" onclick=\"setScanTab('camera')\" id=\"tabCamera\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z\"/><circle cx=\"12\" cy=\"13\" r=\"4\"/></svg>\n                Caméra\n            </button>\n        </div>\n        <div id=\"scanPanelUpload\">\n            <label class=\"scan-dropzone\" id=\"scanDropzone\" for=\"scanFileInput\">\n                <input type=\"file\" id=\"scanFileInput\" accept=\"image/*\" multiple style=\"display:none\" onchange=\"handleFileSelect(this.files)\">\n                <div class=\"scan-drop-icon\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"3\"/><circle cx=\"8.5\" cy=\"8.5\" r=\"1.5\"/><polyline points=\"21 15 16 10 5 21\"/></svg></div>\n                <div class=\"scan-drop-text\">Glissez une photo ici</div>\n                <div class=\"scan-drop-sub\">ou cliquez pour parcourir · JPG, PNG, WEBP</div>\n            </label>\n            <div id=\"scanPreviewUpload\" class=\"scan-preview-wrap\" style=\"display:none\"></div>\n        </div>\n        <div id=\"scanPanelCamera\" style=\"display:none\">\n            <div class=\"scan-camera-wrap\">\n                <video id=\"scanVideo\" autoplay playsinline muted></video>\n                <div class=\"scan-camera-overlay\"><div class=\"scan-frame\"></div></div>\n                <canvas id=\"scanCanvas\" style=\"display:none\"></canvas>\n            </div>\n            <div id=\"scanPreviewCamera\" class=\"scan-preview-wrap\" style=\"display:none\"></div>\n            <div style=\"display:flex;gap:8px;margin-top:12px;\">\n                <button class=\"btn-capture\" onclick=\"capturePhoto()\" id=\"btnCapture\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><circle cx=\"12\" cy=\"12\" r=\"4\" fill=\"currentColor\" stroke=\"none\"/></svg> Capturer</button>\n                <button class=\"btn-retake\" onclick=\"retakePhoto()\" id=\"btnRetake\" style=\"display:none\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M1 4v6h6\"/><path d=\"M3.51 15a9 9 0 1 0 .49-4.7\"/></svg> Reprendre</button>\n            </div>\n        </div>\n        <div id=\"scanStatus\" class=\"scan-status\" style=\"display:none\"></div>\n        <div class=\"form-actions\" style=\"margin-top:16px;\">\n            <button type=\"button\" class=\"btn-cancel\" onclick=\"closeScanModal()\">Annuler</button>\n            <button type=\"button\" class=\"btn-submit\" id=\"btnAnalyse\" onclick=\"analyseImages()\" disabled>Identifier</button>\n        </div>\n    </div>\n</div>\n\n<script>\nlet scanTab = 'upload';\nlet scanImages = [];\nlet cameraStream = null;\nlet capturedDataUrl = null;\nlet onScanFormClose = null;\n\nfunction openScanModal() {\n    scanImages = [];\n    capturedDataUrl = null;\n    document.getElementById('scanFileInput').value = '';\n    document.getElementById('scanPreviewUpload').style.display = 'none';\n    document.getElementById('scanPreviewUpload').innerHTML = '';\n    document.getElementById('scanPreviewCamera').style.display = 'none';\n    document.getElementById('scanPreviewCamera').innerHTML = '';\n    document.getElementById('scanStatus').style.display = 'none';\n    document.getElementById('btnAnalyse').disabled = true;\n    document.getElementById('btnRetake').style.display = 'none';\n    document.getElementById('btnCapture').style.display = 'flex';\n    setScanTab('upload');\n    document.getElementById('scanModalOverlay').classList.add('active');\n}\n\nfunction closeScanModal() {\n    document.getElementById('scanModalOverlay').classList.remove('active');\n    stopCamera();\n}\n\ndocument.getElementById('scanModalOverlay').addEventListener('click', e => {\n    if (e.target === document.getElementById('scanModalOverlay')) closeScanModal();\n});\n\nfunction setScanTab(tab) {\n    scanTab = tab;\n    document.getElementById('tabUpload').classList.toggle('active', tab === 'upload');\n    document.getElementById('tabCamera').classList.toggle('active', tab === 'camera');\n    document.getElementById('scanPanelUpload').style.display = tab === 'upload' ? '' : 'none';\n    document.getElementById('scanPanelCamera').style.display = tab === 'camera' ? '' : 'none';\n    if (tab === 'camera') startCamera(); else stopCamera();\n}\n\nconst dropzone = document.getElementById('scanDropzone');\ndropzone.addEventListener('dragover', e => { e.preventDefault(); dropzone.classList.add('drag-over'); });\ndropzone.addEventListener('dragleave', () => dropzone.classList.remove('drag-over'));\ndropzone.addEventListener('drop', e => { e.preventDefault(); dropzone.classList.remove('drag-over'); handleFileSelect(e.dataTransfer.files); });\n\nfunction handleFileSelect(files) {\n    if (!files || !files.length) return;\n    Array.from(files).forEach(file => {\n        if (!file.type.startsWith('image/')) return;\n        const reader = new FileReader();\n        reader.onload = e => { scanImages.push({ dataUrl: e.target.result }); renderUploadPreviews(); };\n        reader.readAsDataURL(file);\n    });\n}\n\nfunction renderUploadPreviews() {\n    const wrap = document.getElementById('scanPreviewUpload');\n    wrap.innerHTML = '';\n    scanImages.forEach((img, i) => {\n        const div = document.createElement('div');\n        div.className = 'scan-preview-item';\n        div.innerHTML = `<img src=\"${img.dataUrl}\"><button class=\"scan-remove\" onclick=\"removeScanImage(${i})\">✕</button>`;\n        wrap.appendChild(div);\n    });\n    wrap.style.display = scanImages.length ? 'flex' : 'none';\n    document.getElementById('btnAnalyse').disabled = scanImages.length === 0;\n    document.getElementById('scanStatus').style.display = 'none';\n}\n\nfunction removeScanImage(i) { scanImages.splice(i, 1); renderUploadPreviews(); }\n\nasync function startCamera() {\n    try {\n        cameraStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false });\n        document.getElementById('scanVideo').srcObject = cameraStream;\n    } catch(e) { showScanStatus('error', 'Caméra inaccessible. Vérifiez les permissions.'); }\n}\n\nfunction stopCamera() {\n    if (cameraStream) { cameraStream.getTracks().forEach(t => t.stop()); cameraStream = null; }\n}\n\nfunction capturePhoto() {\n    const video = document.getElementById('scanVideo');\n    const canvas = document.getElementById('scanCanvas');\n    canvas.width = video.videoWidth; canvas.height = video.videoHeight;\n    canvas.getContext('2d').drawImage(video, 0, 0);\n    capturedDataUrl = canvas.toDataURL('image/jpeg', 0.85);\n    const wrap = document.getElementById('scanPreviewCamera');\n    wrap.innerHTML = `<div class=\"scan-preview-item\"><img src=\"${capturedDataUrl}\"></div>`;\n    wrap.style.display = 'flex';\n    document.getElementById('scanVideo').style.display = 'none';\n    document.querySelector('.scan-camera-overlay').style.display = 'none';\n    document.getElementById('btnCapture').style.display = 'none';\n    document.getElementById('btnRetake').style.display = 'flex';\n    document.getElementById('btnAnalyse').disabled = false;\n}\n\nfunction retakePhoto() {\n    capturedDataUrl = null;\n    document.getElementById('scanPreviewCamera').style.display = 'none';\n    document.getElementById('scanPreviewCamera').innerHTML = '';\n    document.getElementById('scanVideo').style.display = '';\n    document.querySelector('.scan-camera-overlay').style.display = '';\n    document.getElementById('btnCapture').style.display = 'flex';\n    document.getElementById('btnRetake').style.display = 'none';\n    document.getElementById('btnAnalyse').disabled = true;\n    document.getElementById('scanStatus').style.display = 'none';\n}\n\nfunction showScanStatus(type, msg) {\n    const el = document.getElementById('scanStatus');\n    el.className = 'scan-status' + (type ? ' ' + type : '');\n    el.style.display = 'flex';\n    const spinSvg = `<svg class=\"spin\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 12a9 9 0 1 1-6.219-8.56\"/></svg>`;\n    const okSvg = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"m5 12 5 5L20 7\"/></svg>`;\n    const errSvg = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"m15 9-6 6M9 9l6 6\"/></svg>`;\n    const ico = type === '' ? spinSvg : type === 'success' ? okSvg : errSvg;\n    el.innerHTML = `${ico}<span>${msg}</span>`;\n}\n\nasync function analyseImages() {\n    document.getElementById('btnAnalyse').disabled = true;\n    showScanStatus('', 'Identification en cours…');\n    const images = scanTab === 'camera' ? (capturedDataUrl ? [{ dataUrl: capturedDataUrl }] : []) : scanImages;\n    if (!images.length) return;\n\n    const results = [];\n    for (const img of images) {\n        const base64 = img.dataUrl.split(',')[1];\n        const mediaType = img.dataUrl.startsWith('data:image/png') ? 'image/png' : img.dataUrl.startsWith('data:image/webp') ? 'image/webp' : 'image/jpeg';\n        try {\n            const res = await fetch('https://api.anthropic.com/v1/messages', {\n                method: 'POST',\n                headers: { 'Content-Type': 'application/json' },\n                body: JSON.stringify({\n                    model: 'claude-sonnet-4-6', max_tokens: 1000,\n                    messages: [{ role: 'user', content: [\n                        { type: 'image', source: { type: 'base64', media_type: mediaType, data: base64 } },\n                        { type: 'text', text: `Tu es un expert en cartes Pokémon. Analyse cette image et identifie la carte.\\nRéponds UNIQUEMENT avec un objet JSON valide (pas de markdown), avec ces champs :\\n{\"carte\":\"NOM EN MAJUSCULES\",\"numero\":\"ex: 006/165\",\"bloc\":\"ECARLATE ET VIOLET|EPEE ET BOUCLIER|SOLEIL ET LUNE|XY|MEGA EVOLUTION|Inconnu\",\"serie\":\"NOM EN MAJUSCULES\",\"confiance\":\"haute|moyenne|faible\"}\\nSi tu ne peux pas identifier, retourne {\"erreur\":\"raison\"}.` }\n                    ]}]\n                })\n            });\n            const data = await res.json();\n            const text = data.content?.map(b => b.text || '').join('') || '';\n            let parsed;\n            try { parsed = JSON.parse(text.trim()); }\n            catch(e) { const m = text.match(/\\{[\\s\\S]*\\}/); parsed = m ? JSON.parse(m[0]) : { erreur: 'Réponse inattendue' }; }\n            results.push(parsed);\n        } catch(e) { results.push({ erreur: 'Erreur réseau : ' + e.message }); }\n    }\n\n    const valid = results.filter(r => !r.erreur);\n    const errors = results.filter(r => r.erreur);\n    if (!valid.length) {\n        showScanStatus('error', errors[0]?.erreur || 'Aucune carte identifiée.');\n        document.getElementById('btnAnalyse').disabled = false;\n        return;\n    }\n\n    showScanStatus('success', 'Carte identifiée !');\n    setTimeout(() => {\n        closeScanModal();\n        prefillAndOpenModal(valid[0]);\n    }, 700);\n}\n\nfunction prefillAndOpenModal(result) {\n    document.getElementById('itemForm').reset();\n    document.getElementById('formItemIndex').value = '-1';\n    document.getElementById('modalTitle').textContent = result.confiance !== 'haute' ? 'Vérifier et ajouter ⚠️' : 'Vérifier et ajouter';\n    document.getElementById('btnSubmitForm').textContent = 'Ajouter';\n    document.getElementById('formCarte').value = result.carte || '';\n    document.getElementById('formNumero').value = result.numero || '';\n    document.getElementById('formSerie').value = result.serie || '';\n    const sel = document.getElementById('formBloc');\n    const bloc = result.bloc || 'Inconnu';\n    if (!Array.from(sel.options).some(o => o.value === bloc)) sel.add(new Option(bloc, bloc));\n    sel.value = bloc;\n    document.getElementById('modalOverlay').classList.add('active');\n}\n</script>\n\n<!-- BULK ACTION BAR -->\n<div class=\"bulk-bar\" id=\"bulkBar\">\n    <span class=\"bulk-count\" id=\"bulkCount\">0 sélectionné</span>\n    <div class=\"bulk-sep\"></div>\n    <button class=\"bulk-btn bulk-btn-ebay\" onclick=\"bulkEbay()\" title=\"Actualiser eBay\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 8v4l2.5 2.5\"/></svg>\n        eBay\n    </button>\n    <button class=\"bulk-btn bulk-btn-edit\" onclick=\"openBulkEditModal()\" title=\"Modifier\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7\"/><path d=\"M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z\"/></svg>\n        Modifier\n    </button>\n    <button class=\"bulk-btn bulk-btn-del\" onclick=\"bulkDelete()\" title=\"Supprimer\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"3 6 5 6 21 6\"/><path d=\"M19 6l-1 14H6L5 6\"/><path d=\"M10 11v6M14 11v6\"/><path d=\"M9 6V4h6v2\"/></svg>\n        Supprimer\n    </button>\n    <div class=\"bulk-sep\"></div>\n    <div class=\"bulk-progress\" id=\"bulkProgress\"><div class=\"bulk-progress-bar\" id=\"bulkProgressBar\"></div></div>\n    <button class=\"bulk-close\" onclick=\"clearSelection()\" title=\"Annuler la sélection\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M18 6 6 18M6 6l12 12\"/></svg>\n    </button>\n</div>\n\n<!-- BULK EDIT MODAL -->\n<div class=\"modal-overlay\" id=\"bulkEditOverlay\">\n    <div class=\"modal bulk-edit-modal\">\n        <div class=\"modal-head\">\n            <span class=\"modal-title\" id=\"bulkEditTitle\">Modifier la sélection</span>\n            <button class=\"modal-close\" onclick=\"closeBulkEditModal()\" aria-label=\"Fermer\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M18 6 6 18M6 6l12 12\"/></svg>\n            </button>\n        </div>\n        <div class=\"bulk-field-hint\">Cochez les champs à modifier. Seuls les champs cochés seront appliqués.</div>\n        <div id=\"bulkFieldsContainer\"></div>\n        <div class=\"form-actions\">\n            <button type=\"button\" class=\"btn-cancel\" onclick=\"closeBulkEditModal()\">Annuler</button>\n            <button type=\"button\" class=\"btn-submit\" onclick=\"applyBulkEdit()\">Appliquer</button>\n        </div>\n    </div>\n</div>\n\n\n<script id=\"bulk-js\">\n// Références page\nconst _currentData = cartesData;\nfunction _ebayQuery(row) { return row.carte + ' ' + row.numero + ' pokemon card'; }\nconst _pageFields = [{\"key\": \"carte\", \"label\": \"Nom carte\", \"type\": \"text\", \"placeholder\": \"Dracaufeu EX\"},\n{\"key\": \"numero\", \"label\": \"Numéro\", \"type\": \"text\", \"placeholder\": \"006/165\"},\n{\"key\": \"bloc\", \"label\": \"Bloc\", \"type\": \"select\", \"options\": [{\"v\": \"ECARLATE ET VIOLET\", \"l\": \"Écarlate et Violet\"}, {\"v\": \"EPEE ET BOUCLIER\", \"l\": \"Épée et Bouclier\"}, {\"v\": \"SOLEIL ET LUNE\", \"l\": \"Soleil et Lune\"}, {\"v\": \"XY\", \"l\": \"XY\"}, {\"v\": \"MEGA EVOLUTION\", \"l\": \"Mega Evolution\"}, {\"v\": \"Inconnu\", \"l\": \"Autre/Inconnu\"}]},\n{\"key\": \"serie\", \"label\": \"Série\", \"type\": \"text\", \"placeholder\": \"151\"},\n{\"key\": \"prix_achat\", \"label\": \"Prix achat\", \"type\": \"number\", \"placeholder\": \"0.00\", \"step\": \"0.01\", \"min\": \"0\"},\n{\"key\": \"cote\", \"label\": \"Cote (€)\", \"type\": \"number\", \"placeholder\": \"0.00\", \"step\": \"0.01\", \"min\": \"0\"}];\n\n// ===== BULK SELECTION =====\nlet selectedIndices = new Set();\n\nfunction toggleSelectAll(cb) {\n    const rows = document.querySelectorAll('.row-cb');\n    rows.forEach(r => {\n        r.checked = cb.checked;\n        const idx = parseInt(r.dataset.idx);\n        if (cb.checked) selectedIndices.add(idx);\n        else selectedIndices.delete(idx);\n        r.closest('tr').classList.toggle('selected', cb.checked);\n    });\n    updateBulkBar();\n}\n\nfunction toggleRowSelect(cb) {\n    const idx = parseInt(cb.dataset.idx);\n    if (cb.checked) selectedIndices.add(idx);\n    else selectedIndices.delete(idx);\n    cb.closest('tr').classList.toggle('selected', cb.checked);\n    // sync header cb\n    const allCbs = document.querySelectorAll('.row-cb');\n    const headerCb = document.getElementById('selectAllCb');\n    if (headerCb) headerCb.checked = allCbs.length > 0 && [...allCbs].every(c => c.checked);\n    updateBulkBar();\n}\n\nfunction updateBulkBar() {\n    const bar = document.getElementById('bulkBar');\n    const cnt = selectedIndices.size;\n    document.getElementById('bulkCount').textContent = cnt + ' sélectionné' + (cnt > 1 ? 's' : '');\n    bar.classList.toggle('visible', cnt > 0);\n}\n\nfunction clearSelection() {\n    selectedIndices.clear();\n    document.querySelectorAll('.row-cb').forEach(c => { c.checked = false; c.closest('tr').classList.remove('selected'); });\n    const h = document.getElementById('selectAllCb');\n    if (h) h.checked = false;\n    updateBulkBar();\n}\n\n// ===== BULK DELETE =====\nfunction bulkDelete() {\n    const cnt = selectedIndices.size;\n    if (!cnt) return;\n    // custom confirm\n    const overlay = document.createElement('div');\n    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(11,22,35,.45);z-index:500;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(6px);';\n    overlay.innerHTML = `<div style=\"background:white;border-radius:18px;padding:28px 28px 22px;width:360px;max-width:90vw;box-shadow:0 24px 60px rgba(0,0,0,.22);border:1px solid rgba(255,255,255,.9);\">\n        <div style=\"font-size:17px;font-weight:800;color:#111827;margin-bottom:8px;\">Supprimer ${cnt} élément${cnt>1?'s':''} ?</div>\n        <div style=\"font-size:13.5px;color:#6B7280;margin-bottom:22px;line-height:1.55;\">Cette action est irréversible.</div>\n        <div style=\"display:flex;justify-content:flex-end;gap:8px;\">\n            <button id=\"bcCancel\" style=\"background:#EEF0F7;border:none;padding:9px 17px;border-radius:8px;font-family:Manrope,sans-serif;font-size:13px;font-weight:600;cursor:pointer;color:#6B7280;\">Annuler</button>\n            <button id=\"bcConfirm\" style=\"background:#E3350D;color:white;border:none;padding:9px 18px;border-radius:8px;font-family:Manrope,sans-serif;font-size:13px;font-weight:700;cursor:pointer;\">Supprimer</button>\n        </div>\n    </div>`;\n    document.body.appendChild(overlay);\n    overlay.querySelector('#bcCancel').onclick = () => document.body.removeChild(overlay);\n    overlay.querySelector('#bcConfirm').onclick = async () => {\n        document.body.removeChild(overlay);\n        const ids = [...selectedIndices].map(i => _currentData[i]?.id).filter(Boolean);\n        if (ids.length) await _supabaseClient.from('cartes_unite').delete().in('id', ids);\n        const sorted = [...selectedIndices].sort((a,b) => b-a);\n        sorted.forEach(i => _currentData.splice(i, 1));\n        selectedIndices.clear();\n        applyFiltersAndSort();\n        updateBulkBar();\n    };\n}\n\n// ===== BULK EBAY =====\nasync function bulkEbay() {\n    const indices = [...selectedIndices];\n    if (!indices.length) return;\n    const prog = document.getElementById('bulkProgress');\n    const progBar = document.getElementById('bulkProgressBar');\n    prog.style.display = 'block';\n    let done = 0;\n    for (const idx of indices) {\n        const row = _currentData[idx];\n        if (!row) continue;\n        const query = _ebayQuery(row);\n        try {\n            const res = await fetch(`/api/ebay-price?q=${encodeURIComponent(query)}`);\n            const data = await res.json();\n            if (!data.error && data.price !== null) {\n                row.cote = data.price;\n                row.benef = Math.round((data.price - row.prix_achat) * 100) / 100;\n                if (row.id) await _supabaseClient.from('cartes_unite').update({ cote: data.price }).eq('id', row.id);\n            }\n        } catch(e) {}\n        done++;\n        progBar.style.width = (done / indices.length * 100) + '%';\n    }\n    setTimeout(() => {\n        prog.style.display = 'none';\n        progBar.style.width = '0%';\n        applyFiltersAndSort();\n        clearSelection();\n    }, 500);\n}\n\n// ===== BULK EDIT MODAL =====\nfunction openBulkEditModal() {\n    const cnt = selectedIndices.size;\n    if (!cnt) return;\n    document.getElementById('bulkEditTitle').textContent = `Modifier ${cnt} élément${cnt>1?'s':''}`;\n    const container = document.getElementById('bulkFieldsContainer');\n    container.innerHTML = '';\n    _pageFields.forEach(field => {\n        const row = document.createElement('div');\n        row.className = 'bulk-field-row';\n        const inputId = 'bfi_' + field.key;\n        const cbId = 'bfcb_' + field.key;\n        let inputHtml = '';\n        if (field.type === 'select') {\n            inputHtml = `<select class=\"bulk-field-input\" id=\"${inputId}\" disabled>\n                ${field.options.map(o => `<option value=\"${o.v}\">${o.l}</option>`).join('')}\n            </select>`;\n        } else {\n            inputHtml = `<input type=\"${field.type}\" class=\"bulk-field-input\" id=\"${inputId}\" placeholder=\"${field.placeholder||''}\" step=\"${field.step||'any'}\" min=\"${field.min||''}\" disabled>`;\n        }\n        row.innerHTML = `\n            <input type=\"checkbox\" class=\"bulk-field-cb\" id=\"${cbId}\" onchange=\"toggleBulkField('${field.key}')\">\n            <label class=\"bulk-field-label\" for=\"${cbId}\">${field.label}</label>\n            ${inputHtml}`;\n        container.appendChild(row);\n    });\n    document.getElementById('bulkEditOverlay').classList.add('active');\n}\n\nfunction toggleBulkField(key) {\n    const cb = document.getElementById('bfcb_' + key);\n    const input = document.getElementById('bfi_' + key);\n    input.disabled = !cb.checked;\n    if (cb.checked) input.focus();\n}\n\nfunction closeBulkEditModal() {\n    document.getElementById('bulkEditOverlay').classList.remove('active');\n}\n\nfunction applyBulkEdit() {\n    const updates = {};\n    _pageFields.forEach(field => {\n        const cb = document.getElementById('bfcb_' + field.key);\n        if (!cb || !cb.checked) return;\n        const input = document.getElementById('bfi_' + field.key);\n        let val = input.value;\n        if (field.type === 'number') val = parseFloat(val);\n        updates[field.key] = val;\n    });\n    if (!Object.keys(updates).length) { closeBulkEditModal(); return; }\n    selectedIndices.forEach(idx => {\n        const row = _currentData[idx];\n        if (!row) return;\n        Object.assign(row, updates);\n        // recalc benef if prix or cote changed\n        if ('prix_achat' in updates || 'cote' in updates) {\n            row.benef = Math.round((row.cote - row.prix_achat) * 100) / 100;\n        }\n    });\n    closeBulkEditModal();\n    applyFiltersAndSort();\n    clearSelection();\n}\n\ndocument.getElementById('bulkEditOverlay').addEventListener('click', e => {\n    if (e.target === document.getElementById('bulkEditOverlay')) closeBulkEditModal();\n});\n\n\n// ── Toast ──\nwindow.showToast = function(msg, type) {\n    type = type || 'info';\n    var icons = {\n        success: '<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"m5 12 5 5L20 7\"/></svg>',\n        error: '<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"m15 9-6 6M9 9l6 6\"/></svg>',\n        info: '<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 16v-4M12 8h.01\"/></svg>'\n    };\n    var t = document.createElement('div');\n    t.className = 'toast ' + type;\n    t.innerHTML = '<div class=\"toast-icon\">' + (icons[type]||icons.info) + '</div><div>' + msg + '</div><div class=\"toast-progress\"></div>';\n    document.getElementById('toastContainer').appendChild(t);\n    setTimeout(function() { t.classList.add('removing'); setTimeout(function() { t.remove(); }, 250); }, 4000);\n};\n\n// ── Confirm dialog ──\nwindow.showConfirm = function(title, body, onConfirm, confirmLabel, danger) {\n    confirmLabel = confirmLabel || 'Supprimer'; danger = danger !== false;\n    var overlay = document.getElementById('confirmOverlay');\n    document.getElementById('confirmTitle').textContent = title;\n    document.getElementById('confirmBody').textContent = body;\n    var okBtn = document.getElementById('confirmOk');\n    okBtn.textContent = confirmLabel;\n    okBtn.style.background = danger ? 'var(--red)' : 'var(--blue)';\n    overlay.classList.add('active');\n    var close = function() { overlay.classList.remove('active'); };\n    document.getElementById('confirmCancel').onclick = close;\n    overlay.onclick = function(e) { if (e.target === overlay) close(); };\n    okBtn.onclick = function() { close(); onConfirm(); };\n};\n\n// ── Page transitions ──\ndocument.querySelectorAll('a[href]').forEach(function(a) {\n    var href = a.getAttribute('href');\n    if (!href || href.startsWith('#') || href.startsWith('http')) return;\n    a.addEventListener('click', function(e) {\n        e.preventDefault();\n        document.body.style.transition = 'opacity .16s, transform .16s';\n        document.body.style.opacity = '0';\n        document.body.style.transform = 'translateY(-5px)';\n        setTimeout(function() { window.location.href = href; }, 160);\n    });\n});\n\n\n    // ── Theme toggle ──\n    var SUN_SVG = '<circle cx=\"12\" cy=\"12\" r=\"5\"/><path d=\"M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42\"/>';\n    var MOON_SVG = '<path d=\"M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z\"/>';\n\n    function applyTheme(dark) {\n        document.documentElement.setAttribute('data-theme', dark ? 'dark' : 'light');\n        var icon = document.getElementById('themeIcon');\n        var label = document.getElementById('themeLabel');\n        var mIcon = document.getElementById('mobileThemeIcon');\n        if (icon) icon.innerHTML = dark ? SUN_SVG : MOON_SVG;\n        if (label) label.textContent = dark ? 'Mode clair' : 'Mode sombre';\n        if (mIcon) mIcon.innerHTML = dark ? SUN_SVG : MOON_SVG;\n    }\n\n    function toggleTheme() {\n        var dark = document.documentElement.getAttribute('data-theme') !== 'dark';\n        localStorage.setItem('theme', dark ? 'dark' : 'light');\n        applyTheme(dark);\n    }\n\n    (function() {\n        var saved = localStorage.getItem('theme');\n        var prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;\n        applyTheme(saved ? saved === 'dark' : prefersDark);\n    })();\n\n</script>\n\n<!-- Supabase auth + data -->\n<script src=\"https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.js\"></script>\n<script>\n(async function() {\n    const SUPABASE_URL = 'https://gikpqthgpzbsfadvltvt.supabase.co';\n    const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imdpa3BxdGhncHpic2ZhZHZsdHZ0Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODEzNjE2NTEsImV4cCI6MjA5NjkzNzY1MX0.-PAqol9IxvK2tdG9lqlPnybNIqUSgsbJokEYyx9kR0I';\n    const client = supabase.createClient(SUPABASE_URL, SUPABASE_KEY);\n    _supabaseClient = client;\n\n    const { data: { user } } = await client.auth.getUser();\n    if (!user) { window.location.replace('/connexion?redirect=/dashboard'); return; }\n    _currentUser = user;\n\n    const name = user.user_metadata?.full_name || user.email?.split('@')[0] || 'Investisseur';\n    const initial = name.charAt(0).toUpperCase();\n    const nameEl = document.getElementById('userName');\n    const avatarEl = document.getElementById('userAvatar');\n    if (nameEl) nameEl.textContent = name;\n    const tagline = user.user_metadata?.tagline || 'Dresseur·se';\n    const roleEl = document.getElementById('userRole');\n    if (roleEl) roleEl.textContent = tagline;\n    const avatarUrl = user.user_metadata?.avatar_url;\n    if (avatarEl) {\n        if (avatarUrl) {\n            avatarEl.style.padding = '0';\n            avatarEl.innerHTML = '<img src=\"'+avatarUrl+'\" alt=\"'+name+'\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\">';\n        } else {\n            avatarEl.textContent = initial;\n        }\n    }\n\n    window.handleLogout = async function() {\n        await client.auth.signOut();\n        window.location.replace('/connexion');\n    };\n    client.auth.onAuthStateChange((event) => {\n        if (event === 'SIGNED_OUT') window.location.replace('/connexion');\n    });\n\n    // Charger les données depuis Supabase\n    try {\n        const { data: rows, error } = await client.from('cartes_unite').select('*').order('created_at', { ascending: false });\n        if (error) throw error;\n        cartesData = (rows || []).map(r => ({ ...r, benef: r.cote - r.prix_achat }));\n    } catch(e) {\n        showToast('Erreur de chargement des données', 'error');\n    }\n    applyFiltersAndSort();\n})();\n</script>\n</body>\n</html>";
export default html;
